  services?: string;
  website?: string;
  productInfo: string;
  brandTone: string;
  persona: string;
  brandColors: string[];
  targetAudience: string;
  visualStyle: string;
  facebookPageId: string;
  facebookToken: string;
  threadsAccounts?: ThreadsAccount[];
  referenceFiles: { name: string; content: string }[];
  fixedHashtags?: string;
