}

// Viral & DNA
export type ViralType = 'shocking' | 'story' | 'contrarian' | 'educational' | 'listicle' | 'auto';
export type ViralPlatform = 'facebook' | 'instagram' | 'threads' | 'linkedin';

export interface TitleScore {
    title: string;
    score: number;
    breakdown: {
        emotion: number;
        curiosity: number;
        identity: number;
        specific: number;
        authenticity: number;
    };
    comment: string;
}

export interface ViralPostDraft {
    versions: string[];
    imagePrompt: string;
}

export interface DNALabAnalysis {
    species: string;
    visualDescription: string;
    stats: {
        chaos: number;
        chill: number;
        intellect: number;
        aggression: number;
        emo: number;
        luck: number;
    };
