export const YouTubeService = {
    /**
     * Execute Google OAuth for YouTube
     */
    authenticate: async (): Promise<string> => {
        // Helper to get Env safely
        const getGoogleClientId = () => {
            const env = (import.meta as any).env || {};
            return env.VITE_GOOGLE_CLIENT_ID || env.REACT_APP_GOOGLE_CLIENT_ID || '';
        };

        const clientId = getGoogleClientId();

        // STRICT MODE: If client ID is missing, throw error instead of mocking
        if (!clientId) {
            throw new Error("環境變數未設定 VITE_GOOGLE_CLIENT_ID。\n\n請至 Google Cloud Console 建立 OAuth Client ID 並設定於 .env 檔案中。");
        }

        // Return a promise that resolves when the popup flow finishes
        return new Promise((resolve, reject) => {
            try {
                // Ensure Google Identity Services script is loaded
                if (typeof window.google === 'undefined' || !window.google.accounts) {
                    throw new Error("Google Identity Services script not loaded. (請確認 index.html 包含 accounts.google.com/gsi/client)");
                }

                const client = window.google.accounts.oauth2.initTokenClient({
                    client_id: clientId,
                    scope: 'https://www.googleapis.com/auth/youtube.readonly',
                    callback: (response: any) => {
                        if (response.access_token) {
                            resolve(response.access_token);
                        } else {
                            reject(new Error("Google Auth Failed or Cancelled"));
                        }
                    },
                });

                // Trigger Popup
                client.requestAccessToken();

            } catch (e: any) {
                console.error("[YouTube Auth Error]", e);
                reject(e);
            }
        });
    },

    /**
     * Fetch Channel Statistics
     */
    fetchChannelStats: async (token: string) => {
        // If user managed to pass a mock token manually (shouldn't happen with strict mode), fail or handle gracefully.
        if (token.startsWith('mock_')) {
            throw new Error("Invalid Token: Mock token detected in strict mode.");
        }

        try {
            // 1. Get Channel ID (Mine)
            const channelRes = await fetch(`https://www.googleapis.com/youtube/v3/channels?part=snippet,statistics,contentDetails&mine=true&access_token=${token}`);

            if (!channelRes.ok) {
                const errData = await channelRes.json();
                throw new Error(errData.error?.message || "YouTube API Request Failed");
            }

            const channelData = await channelRes.json();

            if (!channelData.items || channelData.items.length === 0) {
                throw new Error("找不到 YouTube 頻道 (請確認您登入的 Google 帳號已建立頻道)");
            }

            const item = channelData.items[0];
            const stats = item.statistics;
            const title = item.snippet.title;

            // 2. Fetch Recent Videos for Engagement Calculation (Last 10 videos)
            const uploadsPlaylistId = item.contentDetails?.relatedPlaylists?.uploads;
            let avgEngagement = 0;
            let avgViews = 0;

            if (uploadsPlaylistId) {
                const videosRes = await fetch(`https://www.googleapis.com/youtube/v3/playlistItems?part=snippet,contentDetails&playlistId=${uploadsPlaylistId}&maxResults=10&access_token=${token}`);
                const videosData = await videosRes.json();

                if (videosData.items && videosData.items.length > 0) {
                    const videoIds = videosData.items.map((v: any) => v.contentDetails.videoId).join(',');
                    const statsRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=statistics&id=${videoIds}&access_token=${token}`);
                    const statsData = await statsRes.json();

                    const totalStats = (statsData.items || []).reduce((acc: any, curr: any) => {
                        return {
                            views: acc.views + parseInt(curr.statistics.viewCount || 0),
                            likes: acc.likes + parseInt(curr.statistics.likeCount || 0),
                            comments: acc.comments + parseInt(curr.statistics.commentCount || 0)
                        };
                    }, { views: 0, likes: 0, comments: 0 });

                    const count = statsData.items.length;
                    if (count > 0) {
                        avgViews = Math.round(totalStats.views / count);
                        // Engagement: (Likes+Comments)/Views * 100
                        if (totalStats.views > 0) {
                            avgEngagement = parseFloat((((totalStats.likes + totalStats.comments) / totalStats.views) * 100).toFixed(2));
                        }
                    }
                }
            }

            return {
                title: title,
                subscriberCount: parseInt(stats.subscriberCount),
                videoCount: parseInt(stats.videoCount),
                viewCount: parseInt(stats.viewCount),
                avgEngagement: avgEngagement,
                avgViews: avgViews
            };

        } catch (e: any) {
            console.error("YouTube API Error", e);
            throw new Error(e.message || "YouTube 資料讀取失敗");
        }
    }
};

import { UserProfile, AdminKey, SystemConfig, UsageLog, SocialCard, Campaign } from '../types';

const DB_USERS = 'autosocial_db_users';
const DB_KEYS = 'autosocial_keys';
const DB_CONFIG = 'sys_config';
const DB_LOGS = 'autosocial_logs';
const DB_CONNECT_PROFILES = 'autosocial_connect_profiles'; // New
const DB_CAMPAIGNS = 'autosocial_campaigns'; // New

// Helper to get raw DB object
const getDb = (key: string) => {
    try {
        return JSON.parse(localStorage.getItem(key) || '{}');
    } catch (e) {
        return {};
    }
};

const getList = <T>(key: string): T[] => {
    try {
        return JSON.parse(localStorage.getItem(key) || '[]');
    } catch (e) {
        return [];
    }
}

const saveDb = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

export const MockStore = {
    // Users
    getUser: (uid: string): UserProfile | null => getDb(DB_USERS)[uid] || null,
    saveUser: (user: UserProfile) => {
        const users = getDb(DB_USERS);
        users[user.user_id] = user;
        saveDb(DB_USERS, users);
    },
    getAllUsers: (): UserProfile[] => Object.values(getDb(DB_USERS)),
    findUserByEmail: (email: string): UserProfile | undefined => Object.values(getDb(DB_USERS)).find((u: any) => u.email === email) as UserProfile,
    findUserByReferral: (code: string): UserProfile | undefined => Object.values(getDb(DB_USERS)).find((u: any) => u.referralCode === code) as UserProfile,

    // Keys
    getKey: (key: string): AdminKey | null => getDb(DB_KEYS)[key] || null,
    saveKey: (keyData: AdminKey) => {
        const keys = getDb(DB_KEYS);
        keys[keyData.key] = keyData;
        saveDb(DB_KEYS, keys);
    },

    // Config
    getConfig: (): SystemConfig => JSON.parse(localStorage.getItem(DB_CONFIG) || '{"maintenanceMode": false, "dryRunMode": false}'),
    saveConfig: (config: SystemConfig) => localStorage.setItem(DB_CONFIG, JSON.stringify(config)),

    // Logs
    saveLog: (log: UsageLog) => {
       const logs = JSON.parse(localStorage.getItem(DB_LOGS) || '[]');
       logs.push(log);
       localStorage.setItem(DB_LOGS, JSON.stringify(logs));
    },

    // Connect Profiles (Social Cards)
    getConnectProfile: (userId: string): SocialCard | null => getDb(DB_CONNECT_PROFILES)[userId] || null,
    saveConnectProfile: (card: SocialCard) => {
        const profiles = getDb(DB_CONNECT_PROFILES);
        profiles[card.userId] = card;
        saveDb(DB_CONNECT_PROFILES, profiles);
    },
    getAllConnectProfiles: (): SocialCard[] => Object.values(getDb(DB_CONNECT_PROFILES)),

    // Campaigns
    getAllCampaigns: (): Campaign[] => getList(DB_CAMPAIGNS),
    saveCampaign: (campaign: Campaign) => {
        const list = getList<Campaign>(DB_CAMPAIGNS);
        const idx = list.findIndex(c => c.id === campaign.id);
        if (idx >= 0) list[idx] = campaign;
        else list.unshift(campaign);
        saveDb(DB_CAMPAIGNS, list);
    },
    deleteCampaign: (id: string) => {
        const list = getList<Campaign>(DB_CAMPAIGNS).filter(c => c.id !== id);
        saveDb(DB_CAMPAIGNS, list);
    }
};

import { ThreadsAccount } from "../types";

const THREADS_API_BASE = 'https://graph.threads.net/v1.0';
const THREADS_GRAPH_BASE = 'https://graph.threads.net';

// Helper to get Env safely
const getThreadsAppId = () => {
    const env = (import.meta as any).env || {};
    return env.VITE_THREADS_APP_ID || env.REACT_APP_THREADS_APP_ID || '';
};

/**
 * Publishes a TEXT post to Threads.
 * Note: Threads API for Image/Video requires a public URL accessible by Meta's servers.
 */
export const publishThreadsPost = async (
  account: ThreadsAccount,
  text: string,
  imageUrl?: string,
  replyToId?: string // New: Optional param for replying
): Promise<{ success: boolean; id?: string; error?: string }> => {

  if (!account.userId || !account.token) {
    return { success: false, error: '帳號設定不完整 (缺 ID 或 Token)' };
  }

  try {
    // 1. Create Media Container
    const params = new URLSearchParams();
    params.append('access_token', account.token);
    params.append('text', text);

    if (replyToId) {
        params.append('reply_to_id', replyToId);
    }

    let endpoint = `${THREADS_API_BASE}/${account.userId}/threads`;

    // Attempt Image if URL is public (http/https)
    if (imageUrl && (imageUrl.startsWith('http://') || imageUrl.startsWith('https://'))) {
        params.append('media_type', 'IMAGE');
        params.append('image_url', imageUrl);
    } else {
        params.append('media_type', 'TEXT');
    }

    const containerRes = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: params
    });

    const containerData = await containerRes.json();

    if (containerData.error) {
        throw new Error(`建立貼文容器失敗: ${containerData.error.message}`);
    }

    const creationId = containerData.id;

    // 2. Publish Media Container
    const publishParams = new URLSearchParams();
    publishParams.append('access_token', account.token);
    publishParams.append('creation_id', creationId);

    const publishRes = await fetch(`${THREADS_API_BASE}/${account.userId}/threads_publish`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: publishParams
    });

    const publishData = await publishRes.json();

    if (publishData.error) {
        throw new Error(`發佈貼文失敗: ${publishData.error.message}`);
    }

    return { success: true, id: publishData.id };

  } catch (e: any) {
    console.error("Threads API Error:", e);
    return { success: false, error: e.message };
  }
};

/**
 * Fetch User's Recent Threads
 */
export const fetchUserThreads = async (account: ThreadsAccount, limit = 5) => {
    try {
        const fields = 'id,text,permalink,timestamp,media_type,media_url';
        const url = `${THREADS_API_BASE}/${account.userId}/threads?fields=${fields}&limit=${limit}&access_token=${account.token}`;
        const res = await fetch(url);
        const data = await res.json();
        if (data.error) throw new Error(data.error.message);
        return data.data || [];
    } catch (e: any) {
        console.error("Fetch threads failed", e);
        // Throw error to UI instead of silent fail, so user knows if token is invalid
        throw new Error(e.message || "讀取貼文失敗");
    }
};

/**
 * Fetch Replies for a specific Media Object (Thread)
 */
export const fetchMediaReplies = async (account: ThreadsAccount, mediaId: string) => {
